INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1d8b8153-db3d-496e-84da-5ee1d9e3a130',
  '00000000-0000-0000-0000-000000000001',
  $escape$Cypress + Vitest — Fast Unit Tests for the Logic Your Cypress Specs Can't Cheaply Cover$escape$,
  $escape$Cypress excels at E2E and component testing, but spinning up a browser to validate a URL builder or a state reducer is wasteful. Vitest fills the unit layer without adding tooling friction — if your project already uses Vite (common with Cypress component testing setups), Vitest shares the same `vite.config.ts` with zero extra config.

The API is Jest-compatible: `describe`, `it`, `expect`, `vi.fn()`, `vi.spyOn()`. If you've written Cypress custom commands or tested pure utility logic before, you're already familiar. Vitest resolves modules through Vite's pipeline, so `import.meta.env` values — the same ones your `cypress.config.ts` reads via `defineConfig` — work identically in tests.

The sharpest Vitest feature is in-source testing: embed test blocks directly inside source files using an `if (import.meta.vitest)` guard. These blocks are tree-shaken out of production builds automatically. Use this for utilities you also reference inside Cypress custom commands — the logic is tested co-located, not buried in a separate `__tests__` folder.

Pair Cypress for integration flows, Vitest for the pure-logic base of your test pyramid.$escape$,
  $escape$// src/utils/buildApiUrl.ts
export function buildApiUrl(path: string, params?: Record<string, string>): string {
  const base = import.meta.env.VITE_API_URL ?? 'http://localhost:3000'
  const url = new URL(path, base)
  if (params) Object.entries(params).forEach(([k, v]) => url.searchParams.set(k, v))
  return url.toString()
}

// in-source tests — tree-shaken in prod, run instantly by Vitest
if (import.meta.vitest) {
  const { it, expect } = import.meta.vitest
  it('appends query params correctly', () => {
    expect(buildApiUrl('/users', { role: 'admin' })).toContain('role=admin')
  })
  it('falls back to localhost when env is unset', () => {
    expect(buildApiUrl('/ping')).toMatch(/localhost:3000/)
  })
}$escape$,
